function $(id){return document.getElementById(id)}
function todayKey(d=new Date()){return d.toISOString().slice(0,10)}
function load(){try{return JSON.parse(localStorage.getItem(STORAGE_KEY))||{}}catch(e){return {}}}
let state=load();
state.section=state.section||'ethics'; state.view=state.view||'dashboard'; state.scores=state.scores||{}; state.flash=state.flash||{}; state.sim=state.sim||{}; state.quizLimit=state.quizLimit||10; state.currentQuiz=state.currentQuiz||{}; state.simLimit=state.simLimit||1; state.currentSims=state.currentSims||{}; state.notes=state.notes||''; state.missed=state.missed||{}; state.progress=state.progress||{}; state.examHistory=state.examHistory||[]; state.examDate=state.examDate||defaultExamDate(); state.calendarView=state.calendarView||'week'; state.examRun=state.examRun||null;
function defaultExamDate(){let d=new Date(); d.setDate(d.getDate()+42); return d.toISOString().slice(0,10)}
function save(){localStorage.setItem(STORAGE_KEY,JSON.stringify(state))}
function shuffle(a){a=a.slice();for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}
function areaQs(sec=state.section){return QUESTIONS.filter(q=>q.sec===sec)}
function areaFlash(sec=state.section){return FLASH.filter(f=>f.sec===sec)}
function areaSims(sec=state.section){return SIMS.filter(s=>s.sec===sec)}
function sectionName(id){let s=SECTIONS.find(x=>x.id===id); return s?`Area ${s.roman}: ${s.name}`:id}
function setView(v){state.view=v;save();render()}
function setSection(sec){state.section=sec;save();render()}
function renderSections(){$('sections').innerHTML=SECTIONS.map(s=>`<button class="section ${state.section===s.id?'active':''}" onclick="setSection('${s.id}')">Area ${s.roman}</button>`).join('')}
function renderNav(){let names=[['dashboard','Dashboard'],['calendar','Calendar'],['quiz','MCQs'],['sims','Simulations'],['flash','Flashcards'],['read','Readings'],['exam','Exam Mode'],['missed','Missed Questions'],['progress','Progress Log'],['notes','Notes']];$('nav').innerHTML=names.map(n=>`<button class="${state.view===n[0]?'active':''}" onclick="setView('${n[0]}')">${n[1]}</button>`).join('')}
function logActivity(type,sec,detail){let k=todayKey(); state.progress[k]=state.progress[k]||[]; state.progress[k].push({time:new Date().toLocaleTimeString(),type,sec,detail}); save()}
function readiness(sec){let qs=areaQs(sec), attempted=qs.filter(q=>state.scores[q.id]);let pct=attempted.length?Math.round(attempted.filter(q=>state.scores[q.id].correct).length/attempted.length*100):0;let fs=areaFlash(sec), mast=fs.filter(f=>state.flash[f.id]==='mastered').length;return Math.round(pct*.75+(fs.length?mast/fs.length*100:0)*.25)}
function overallScore(){let vals=Object.values(state.scores); if(!vals.length)return 0; return Math.round(vals.filter(v=>v.correct).length/vals.length*100)}
function daysToExam(){return Math.ceil((new Date(state.examDate+'T23:59:59')-new Date())/86400000)}
function render(){renderSections();renderNav();({dashboard,calendar,quiz,sims,flash,read,exam,missed,progress,notes}[state.view]||dashboard)()}
function dashboard(){let missedCount=Object.keys(state.missed).length; $('app').innerHTML=`<div class="grid"><div class="card"><b>Days to Exam</b><div class="metric">${Math.max(0,daysToExam())}</div><p class="muted">Exam date: ${state.examDate}</p></div><div class="card"><b>Running Score</b><div class="metric">${overallScore()}%</div><p class="muted">Based on attempted MCQs.</p></div><div class="card"><b>Missed Questions</b><div class="metric">${missedCount}</div><p class="muted">Automatically captured.</p></div><div class="card"><b>Exam Attempts</b><div class="metric">${state.examHistory.length}</div><p class="muted">Mock/practice exams completed.</p></div></div><div class="grid">${SECTIONS.map(s=>`<div class="card"><b>Area ${s.roman}: ${s.name}</b><div class="metric">${readiness(s.id)}%</div><div class="bar"><span style="width:${readiness(s.id)}%"></span></div><p class="muted">${areaQs(s.id).length} MCQs · ${areaSims(s.id).length} simulations · ${areaFlash(s.id).length} flashcards · Weight: ${s.weight}</p></div>`).join('')}</div>`}
function quickSize(n){$('sample').value=n;startQuiz()}
function quiz(){let total=areaQs().length;let ids=state.currentQuiz[state.section]||[];$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — MCQ Setup</h2><p class="muted">${total} unique questions available. Questions are selected without duplicate concept IDs.</p><div class="actions"><button onclick="quickSize(10)">10</button><button onclick="quickSize(20)">20</button><button onclick="quickSize(30)">30</button><button onclick="quickSize(50)">50</button><button onclick="quickSize(${total})">All</button><label>Custom <input id="sample" type="number" min="1" max="${total}" value="${Math.min(state.quizLimit,total)}"></label><button class="primary" onclick="startQuiz()">Start New Quiz</button></div></div><div id="quizRun"></div>`; if(ids.length) renderQuizRun()}
function selectUniqueQuestions(pool,n){let used=new Set(), result=[]; for(let q of shuffle(pool)){if(!used.has(q.conceptId)){used.add(q.conceptId);result.push(q)} if(result.length>=n)break} return result}
function startQuiz(){let total=areaQs().length;let n=Math.max(1,Math.min(Number($('sample').value||10),total));state.quizLimit=n;state.currentQuiz[state.section]=selectUniqueQuestions(areaQs(),n).map(q=>q.id);logActivity('MCQ Quiz Started',state.section,`${n} questions`);save();renderQuizRun()}
function renderQuizRun(){let ids=state.currentQuiz[state.section]||[];let qs=ids.map(id=>QUESTIONS.find(q=>q.id===id)).filter(Boolean);$('quizRun').innerHTML=qs.map((q,i)=>`<div class="card"><p class="muted">Question ${i+1} of ${qs.length} · ${q.topic} · ${q.difficulty}</p><h3>${q.q}</h3>${q.choices.map((c,j)=>`<button class="choice" onclick="answer('${q.id}','${'ABCD'[j]}',this)">${'ABCD'[j]}. ${c}</button>`).join('')}<div id="fb-${q.id}"></div></div>`).join('')}
function answer(id,letter,btn){let q=QUESTIONS.find(x=>x.id===id);let correct=letter===q.ans;state.scores[id]={correct,letter,date:new Date().toISOString(),sec:q.sec,topic:q.topic}; if(!correct){let m=state.missed[id]||{count:0}; state.missed[id]={id,sec:q.sec,topic:q.topic,q:q.q,choices:q.choices,ans:q.ans,lastAnswer:letter,exp:q.exp,count:m.count+1,lastMissed:new Date().toISOString()}} logActivity(correct?'MCQ Correct':'MCQ Missed',q.sec,`${q.topic}: ${q.id}`);save();btn.classList.add(correct?'correct':'wrong');$(`fb-${id}`).innerHTML=`<p><b>${correct?'Correct.':'Incorrect.'}</b> ${q.exp}</p>`}
function quickSim(n){state.simLimit=n;startSims()}
function sims(){let total=areaSims().length;$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Simulation Setup</h2><p class="muted">${total} CPA-style task-based simulations available.</p><div class="actions"><button onclick="quickSim(1)">1 Simulation</button><button onclick="quickSim(2)">2 Simulations</button><button onclick="quickSim(3)">3 Simulations</button><label>Custom <input id="simSample" type="number" min="1" max="${total}" value="${Math.min(state.simLimit,total)}"></label><button class="primary" onclick="startSims()">Start Simulations</button></div></div><div id="simRun"></div>`; if((state.currentSims[state.section]||[]).length) renderSimRun()}
function startSims(){let total=areaSims().length;let el=$('simSample');let n=el?Number(el.value):state.simLimit;n=Math.max(1,Math.min(n||1,total));state.simLimit=n;state.currentSims[state.section]=shuffle(areaSims()).slice(0,n).map(s=>s.id);logActivity('Simulation Set Started',state.section,`${n} simulations`);save();renderSimRun()}
function toggleExhibit(id){let el=$(id); if(el) el.classList.toggle('hide')}
function renderSimRun(){let ids=state.currentSims[state.section]||[];let list=ids.map(id=>SIMS.find(s=>s.id===id)).filter(Boolean);$('simRun').innerHTML=list.map((s,i)=>`<div class="card"><h2>Simulation ${i+1} of ${list.length}: ${s.title}</h2><span class="pill">${s.type}</span><span class="pill">${s.topic}</span><h3>Exhibits</h3><div class="actions">${s.exhibits.map((e,j)=>`<button type="button" onclick="toggleExhibit('${s.id}-ex${j}')">Open ${e}</button>`).join('')}</div>${s.exhibits.map((e,j)=>`<div id="${s.id}-ex${j}" class="card hide"><h3>${e}</h3><pre style="white-space:pre-wrap">${s.exhibitBodies[j]}</pre></div>`).join('')}<p><b>Task:</b> ${s.prompt}</p><ol>${s.tasks.map(t=>`<li>${t}</li>`).join('')}</ol><textarea id="simtxt-${s.id}">${state.sim[s.id]?.text||''}</textarea><h3>Self-check rubric</h3>${s.rubric.map((r,j)=>`<label><input type="checkbox" ${state.sim[s.id]?.checks?.[j]?'checked':''} onchange="saveSim('${s.id}',false)"> ${r}</label><br>`).join('')}<button class="primary" onclick="saveSim('${s.id}',true)">Save Simulation</button><div id="saved-${s.id}"></div></div>`).join('')}
function saveSim(id,show){let boxes=[...document.querySelectorAll(`#simtxt-${id} ~ h3 ~ label input`)];state.sim[id]={text:$(`simtxt-${id}`).value,date:new Date().toISOString(),checks:boxes.map(b=>b.checked)};let sim=SIMS.find(s=>s.id===id);logActivity('Simulation Saved',sim.sec,sim.topic);save();if(show)$(`saved-${id}`).innerHTML='<p>Saved.</p>'}
function flash(){let fs=areaFlash();state.flashIndex=state.flashIndex||{};let idx=Math.min(state.flashIndex[state.section]||0,fs.length-1);let f=fs[idx];let back=state.flashBack==='1';$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Flashcards</h2><p class="muted">Card ${idx+1} of ${fs.length}</p><div class="card"><h3>${back?'Answer / Exam Note':'Prompt'}</h3><p class="metric">${back?f.back:f.front}</p><p><span class="pill">Status: ${state.flash[f.id]||'new'}</span></p><div class="actions"><button onclick="flipFlash()">${back?'Show Prompt':'Flip Card'}</button><button onclick="markFlash('${f.id}','learning')">Learning</button><button class="primary" onclick="markFlash('${f.id}','mastered')">Mastered</button><button onclick="prevFlash()">Previous</button><button onclick="nextFlash()">Next</button></div></div></div>`}
function flipFlash(){state.flashBack=state.flashBack==='1'?'0':'1';save();flash()}
function nextFlash(){let fs=areaFlash();state.flashIndex=state.flashIndex||{};state.flashIndex[state.section]=Math.min((state.flashIndex[state.section]||0)+1,fs.length-1);state.flashBack='0';logActivity('Flashcard Reviewed',state.section,`Card ${state.flashIndex[state.section]+1}`);save();flash()}
function prevFlash(){state.flashIndex=state.flashIndex||{};state.flashIndex[state.section]=Math.max((state.flashIndex[state.section]||0)-1,0);state.flashBack='0';save();flash()}
function markFlash(id,val){state.flash[id]=val;let f=FLASH.find(x=>x.id===id);logActivity(`Flashcard ${val}`,f.sec,f.front);save();flash()}
function read(){let sec=SECTIONS.find(s=>s.id===state.section);let rows=READINGS[state.section]||[];logActivity('Reading Opened',state.section,sec.name);$('app').innerHTML=`<div class="card"><h2>Area ${sec.roman}: ${sec.name}</h2><p class="muted">Substantive review notes organized by topic.</p></div>${rows.map(r=>`<div class="card"><h3>${r.topic}</h3><h4>Key rules</h4><ul>${r.rules.map(x=>`<li>${x}</li>`).join('')}</ul><h4>Common CPA traps</h4><ul>${r.traps.map(x=>`<li>${x}</li>`).join('')}</ul><h4>Exam example</h4><p>${r.example}</p></div>`).join('')}`}
function missed(){let list=Object.values(state.missed).sort((a,b)=>new Date(b.lastMissed)-new Date(a.lastMissed));$('app').innerHTML=`<div class="card"><h2>Missed Questions Log</h2><p class="muted">Incorrect MCQs are automatically added here.</p><div class="actions"><button onclick="startMissedQuiz(10)">Retake 10</button><button onclick="startMissedQuiz(20)">Retake 20</button><button onclick="startMissedQuiz(999)">Retake All</button></div></div>${list.length?list.map(m=>`<div class="card"><b>${sectionName(m.sec)}</b> · ${m.topic} · missed ${m.count} time(s)<p>${m.q}</p><p class="muted">Your last answer: ${m.lastAnswer} · Correct: ${m.ans}</p><p>${m.exp}</p></div>`).join(''):'<div class="card">No missed questions yet.</div>'}`}
function startMissedQuiz(n){let ids=Object.keys(state.missed).slice(0,n); if(!ids.length)return; state.currentQuiz[state.section]=ids; state.view='quiz'; save();render()}
function progress(){let dates=Object.keys(state.progress).sort().reverse();$('app').innerHTML=`<div class="card"><h2>Daily Progress Log</h2><p class="muted">Every quiz, miss, simulation, flashcard, and reading activity is logged by date.</p></div>${dates.length?dates.map(d=>`<div class="card"><h3>${d}</h3><table><tr><th>Time</th><th>Activity</th><th>Area</th><th>Detail</th></tr>${state.progress[d].map(x=>`<tr><td>${x.time}</td><td>${x.type}</td><td>${sectionName(x.sec)}</td><td>${x.detail}</td></tr>`).join('')}</table></div>`).join(''):'<div class="card">No activity logged yet.</div>'}`}
function setExamDate(){state.examDate=$('examDate').value||state.examDate;save();calendar()}
function calendar(){let plan=buildPlan();let days=plan.days;let view=state.calendarView;$('app').innerHTML=`<div class="card"><h2>Live Six-Week Study Calendar</h2><div class="actions"><label>Exam date <input type="date" id="examDate" value="${state.examDate}"></label><button class="primary" onclick="setExamDate()">Save Exam Date</button><button onclick="state.calendarView='day';save();calendar()">Day</button><button onclick="state.calendarView='week';save();calendar()">Week</button><button onclick="state.calendarView='month';save();calendar()">Month</button></div><p><b>${Math.max(0,daysToExam())}</b> days to exam · Running score: <b>${overallScore()}%</b></p></div>${renderCalendarView(days,view)}`}
function buildPlan(){let start=new Date(); let end=new Date(state.examDate+'T12:00:00'); let total=Math.max(1,Math.ceil((end-start)/86400000)); let focus=['ethics','risk','evidence','reporting']; let days=[]; for(let i=0;i<Math.min(42,total);i++){let d=new Date();d.setDate(d.getDate()+i);let sec=focus[i%4];let week=Math.floor(i/7)+1;let intensity=i>34?'Final Review':(i>20?'Mixed Practice':'Build Foundation');days.push({date:todayKey(d),sec,week,intensity,planned:[`${sectionName(sec)} reading`,`${i%3===0?'1 simulation':'20 MCQs'}`,'Flashcards 10','Review missed questions']})}return {days}}
function renderCalendarView(days,view){if(view==='day'){let d=days[0];return `<div class="card"><h3>Today — ${d.date}</h3><p>${d.intensity}</p><ul>${d.planned.map(x=>`<li>${x}</li>`).join('')}</ul><p class="muted">Actual items logged today: ${(state.progress[d.date]||[]).length}</p></div>`} if(view==='week'){let byWeek={};days.forEach(d=>{byWeek[d.week]=byWeek[d.week]||[];byWeek[d.week].push(d)});return Object.keys(byWeek).map(w=>`<div class="card"><h3>Week ${w}</h3><table><tr><th>Date</th><th>Focus</th><th>Plan</th><th>Actual</th></tr>${byWeek[w].map(d=>`<tr><td>${d.date}</td><td>${sectionName(d.sec)}</td><td>${d.planned.join('; ')}</td><td>${(state.progress[d.date]||[]).length} logged</td></tr>`).join('')}</table></div>`).join('')} return `<div class="card"><h3>Month View</h3><div class="calendar">${days.map(d=>`<div class="day"><b>${d.date.slice(5)}</b><br><span class="small">${sectionName(d.sec).replace('Area ','')}</span><br><span class="pill small">${(state.progress[d.date]||[]).length} done</span></div>`).join('')}</div></div>`}
function exam(){if(state.examRun){renderExamRun();return}$('app').innerHTML=`<div class="card"><h2>CPA AUD Exam Mode</h2><p class="muted">Mirrors the current AUD structure: 5 testlets, 78 MCQs, 7 TBSs, 4-hour full exam. MCQ/TBS weighting is tracked separately.</p><div class="actions"><button onclick="startExam('mini')">Mini: 10 MCQs + 1 TBS</button><button onclick="startExam('half')">Half: 39 MCQs + 3 TBSs</button><button class="primary" onclick="startExam('full')">Full Mock: 78 MCQs + 7 TBSs</button></div></div><div class="card"><h3>Previous Exam Attempts</h3>${state.examHistory.length?state.examHistory.map(e=>`<p>${e.date}: ${e.mode} · ${e.score}%</p>`).join(''):'<p>No completed exams yet.</p>'}</div>`}
function startExam(mode){let mcqN=mode==='full'?78:mode==='half'?39:10;let simN=mode==='full'?7:mode==='half'?3:1;let mcqs=selectUniqueQuestions(QUESTIONS,mcqN).map(q=>q.id);let tbss=shuffle(SIMS).slice(0,simN).map(s=>s.id);state.examRun={mode,start:new Date().toISOString(),mcqs,tbss,answers:{},testlet:1,submitted:false};logActivity('Exam Started','ethics',mode);save();renderExamRun()}
function renderExamRun(){let ex=state.examRun; if(!ex)return exam();let mcqItems=ex.mcqs.map(id=>QUESTIONS.find(q=>q.id===id));let simItems=ex.tbss.map(id=>SIMS.find(s=>s.id===id));$('app').innerHTML=`<div class="card"><h2>CPA AUD ${ex.mode.toUpperCase()} Exam</h2><p class="muted">Started ${new Date(ex.start).toLocaleString()}</p><div class="actions"><button class="danger" onclick="state.examRun=null;save();exam()">Exit Exam</button><button class="primary" onclick="submitExam()">Submit Exam</button></div></div><div class="card"><h3>MCQ Testlets</h3>${mcqItems.map((q,i)=>`<div class="examItem"><p class="muted">MCQ ${i+1} of ${mcqItems.length} · ${q.topic}</p><b>${q.q}</b>${q.choices.map((c,j)=>`<label class="choice"><input type="radio" name="ex-${q.id}" value="${'ABCD'[j]}" ${ex.answers[q.id]==='ABCD'[j]?'checked':''} onchange="examAnswer('${q.id}',this.value)"> ${'ABCD'[j]}. ${c}</label>`).join('')}</div>`).join('')}</div><div class="card"><h3>TBS Testlets</h3>${simItems.map((s,i)=>`<div class="examItem"><h4>TBS ${i+1}: ${s.title}</h4><p>${s.prompt}</p><p class="muted">Exhibits available in Simulation practice mode; in this mock, complete your response in notes.</p><textarea onchange="examAnswer('${s.id}',this.value)">${ex.answers[s.id]||''}</textarea></div>`).join('')}</div>`}
function examAnswer(id,val){state.examRun.answers[id]=val;save()}
function submitExam(){let ex=state.examRun;let correct=0;for(let id of ex.mcqs){let q=QUESTIONS.find(x=>x.id===id);if(ex.answers[id]===q.ans)correct++}let mcqPct=ex.mcqs.length?Math.round(correct/ex.mcqs.length*100):0;let tbsPct=ex.tbss.length?Math.round(ex.tbss.filter(id=>(ex.answers[id]||'').trim().length>20).length/ex.tbss.length*100):0;let score=Math.round(mcqPct*.5+tbsPct*.5);state.examHistory.push({date:new Date().toISOString().slice(0,10),mode:ex.mode,score,mcqPct,tbsPct});logActivity('Exam Submitted','ethics',`${ex.mode}: ${score}%`);state.examRun=null;save();$('app').innerHTML=`<div class="card"><h2>Exam Submitted</h2><p>Score estimate: <b>${score}%</b></p><p>MCQ: ${mcqPct}% · TBS completion estimate: ${tbsPct}%</p><button class="primary" onclick="exam()">Back to Exam Mode</button></div>`}
function notes(){$('app').innerHTML=`<div class="card"><h2>Notes</h2><textarea id="notesBox">${state.notes}</textarea><br><button class="primary" onclick="state.notes=$('notesBox').value;logActivity('Note Saved',state.section,'Personal notes updated');save()">Save Notes</button></div>`}
if('serviceWorker' in navigator){navigator.serviceWorker.register('./sw.js').catch(()=>{})}
render();
